5	 * LICENSE file in the root directory of this source tree.
6	 *
7	 *
8	 */
9	
10	'use strict';
11	
12	jest.autoMockOff();
13	
14	import path from 'path';
15	import { transformSync } from '@babel/core';
16	import stylexPlugin from '../src/index';
17	
18	const defaultOpts = {
19	  unstable_moduleResolution: { rootDir: '/stylex/packages/', type: 'commonJS' },
20	};
21	
22	function transform(source, opts = {}) {
23	  const { code, metadata } = transformSync(source, {
24	    filename: opts.filename || '/stylex/packages/TestTheme.stylex.js',
25	    parserOpts: {
26	      flow: 'all',
27	    },
28	    babelrc: false,
29	    plugins: [
30	      [
31	        stylexPlugin,
32	        {
33	          ...defaultOpts,
34	          ...opts,
35	        },
36	      ],
37	    ],
38	  });
39	  return { code, metadata };
40	}
41	
42	function transformWithInlineConsts(source, opts = {}) {
43	  const { code, metadata } = transformSync(source, {
44	    filename: path.join(__dirname, '__fixtures__/main.stylex.js'),
45	    parserOpts: { sourceType: 'module' },
46	    babelrc: false,
47	    plugins: [
48	      [
49	        stylexPlugin,
50	        {
51	          ...opts,
52	          unstable_moduleResolution: {
53	            rootDir: path.join(__dirname, '__fixtures__'),
54	            type: 'commonJS',
55	          },
56	        },
57	      ],
58	    ],
59	  });
60	
61	  return { code, metadata };
62	}
63	
64	describe('@stylexjs/babel-plugin', () => {
65	  describe('[transform] stylex.defineConsts()', () => {
66	    test('constants are unique', () => {
67	      const { code, metadata } = transform(`
68	        import stylex from 'stylex';
69	        export const breakpoints = stylex.defineConsts({ padding: '10px' });
70	      `);
71	
72	      const { code: codeDuplicate, metadata: metadataDuplicate } = transform(`
73	        import stylex from 'stylex';
74	        export const breakpoints = stylex.defineConsts({ padding: '10px' });
75	      `);
76	
77	      // Assert the generated constants are consistent for the same inputs
78	      expect(code).toEqual(codeDuplicate);
79	      expect(metadata).toEqual(metadataDuplicate);
80	
81	      const { code: codeOther, metadata: metadataOther } = transform(`
82	        import stylex from 'stylex';
83	        export const breakpoints = stylex.defineConsts({ margin: '10px' });
84	      `);
85	
86	      // Assert the generated constants are different for different inputs
87	      expect(code).not.toEqual(codeOther);
88	      expect(metadata).not.toEqual(metadataOther);
89	    });
90	
91	    test('constants object', () => {
92	      const { code, metadata } = transform(`
93	        import * as stylex from '@stylexjs/stylex';
94	        export const breakpoints = stylex.defineConsts({
95	          sm: '(min-width: 768px)',
