function evaluatePartialObjectRecursively(
  path: NodePath<t.ObjectExpression>,
  traversalState: StateManager,
  functions: FunctionConfig = { identifiers: {}, memberExpressions: {} },
  keyPath: $ReadOnlyArray<string> = [],
